const https = require('https');
const fs = require('fs');

const token = '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';
const owner = 'doanhieu1986';
const repo = 'vps-automation-vhck';

const pushFile = (path, content, message) => {
  return new Promise((resolve, reject) => {
    const getShaUrl = `/repos/${owner}/${repo}/contents/${path}`;

    const getReq = https.request({
      hostname: 'api.github.com',
      path: getShaUrl,
      method: 'GET',
      headers: {
        'Authorization': `token ${token}`,
        'Accept': 'application/vnd.github.v3+json',
        'User-Agent': 'n8n'
      }
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        let sha = '';
        try {
          const json = JSON.parse(data);
          sha = json.sha || '';
        } catch (e) {}

        const body = JSON.stringify({
          message: message,
          content: content,
          sha: sha,
          branch: 'main'
        });

        const pushReq = https.request({
          hostname: 'api.github.com',
          path: getShaUrl,
          method: 'PUT',
          headers: {
            'Authorization': `token ${token}`,
            'Accept': 'application/vnd.github.v3+json',
            'Content-Type': 'application/json',
            'Content-Length': body.length,
            'User-Agent': 'n8n'
          }
        }, (res) => {
          let respData = '';
          res.on('data', chunk => respData += chunk);
          res.on('end', () => {
            if (res.statusCode >= 400) {
              reject(new Error(`GitHub API error: ${res.statusCode}`));
            } else {
              resolve(respData);
            }
          });
        });

        pushReq.on('error', reject);
        pushReq.write(body);
        pushReq.end();
      });
    });

    getReq.on('error', reject);
    getReq.end();
  });
};

try {
  const htmlPath = '/app/vps-automation-vhck/web/vps_automation_vhck.html';
  const jsonPath = '/app/vps-automation-vhck/data/vsd_records.json';

  let htmlContent = fs.readFileSync(htmlPath, 'utf-8');
  const jsonContent = fs.readFileSync(jsonPath, 'utf-8');
  const jsonData = JSON.parse(jsonContent);

  const recordCount = jsonData.records ? jsonData.records.length : 0;

  const embeddedScript = `
    <script>
      window.EMBEDDED_DATA = ${JSON.stringify(jsonData)};
      console.log('Embedded data loaded: ' + ${recordCount} + ' records');
    </script>
  `;

  htmlContent = htmlContent.replace(/<script>\s*window\.EMBEDDED_DATA = .*?<\/script>/s, '');
  htmlContent = htmlContent.replace('</body>', embeddedScript + '</body>');

  const htmlBase64 = Buffer.from(htmlContent).toString('base64');

  return new Promise(async (resolve) => {
    try {
      await pushFile('index.html', htmlBase64, 'Nhúng dữ liệu VSD vào HTML - ' + new Date().toISOString() + ' (' + recordCount + ' records)');

      resolve([{
        json: {
          status: 'success',
          message: 'Đã deploy lên GitHub Pages với ' + recordCount + ' records embedded',
          github_pages_url: 'https://doanhieu1986.github.io/vps-automation-vhck/',
          records_embedded: recordCount,
          data_embedded: true,
          timestamp: new Date().toISOString()
        }
      }]);
    } catch (error) {
      resolve([{
        json: {
          status: 'error',
          message: error.message
        }
      }]);
    }
  });
} catch (error) {
  return [{
    json: {
      status: 'error',
      message: error.message
    }
  }];
}
